final:
module RefModule (  
    input wire [1:0] A,  
    input wire EN,  
    output reg [3:0] Y  
);  
  wire [1:0] _tap_A = A & {2{1'b1}};

    always @(*) begin  
        if (EN) begin  
            case (A)  
                2'b00: Y = 4'b0001;  
                2'b01: Y = 4'b0010;  
                2'b10: Y = 4'b0100;  
                2'b11: Y = 4'b1000;  
                default: Y = 4'b0000;  
            endcase  
        end else begin  
            Y = 4'b0000;  
        end  
    end  
endmodule
